import{_ as a,o as t,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"46. Breastfeeding","description":"","frontmatter":{"title":"46. Breastfeeding","eba":"Medical Specialists 2022-2026","topics":["hours","breaks","flexible-work"]},"headers":[],"relativePath":"ebas/medical-specialists/accommodation/46-breastfeeding.md","filePath":"ebas/medical-specialists/accommodation/46-breastfeeding.md"}'),o={name:"ebas/medical-specialists/accommodation/46-breastfeeding.md"};function s(n,e,l,c,d,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_46-breastfeeding" tabindex="-1">46. Breastfeeding <a class="header-anchor" href="#_46-breastfeeding" aria-label="Permalink to &quot;46. Breastfeeding&quot;">​</a></h1><p><strong>46.1</strong> Paid break</p><p>Each Health Service will provide reasonable paid break time for a Doctor to express breast milk for her nursing child each time such Doctor has need to express the milk, or breastfeed the child within the workplace, for one year after the child’s birth.</p><p><strong>46.2</strong> Place to express or feed</p><p>Health Services will also provide a comfortable place, other than a bathroom, that is shielded from view and free from intrusion from co-workers and the public, which may be used by a Doctor to express breast milk or breastfeed a child in privacy.</p><p><strong>46.3</strong> Storage</p><p>Appropriate refrigeration will be available in proximity to the area for breast milk storage. Responsibility for labelling, storage and use is with the Doctor.</p><p>Plain language terms: lactation, pumping, expressing milk.</p>',8)])])}const m=a(o,[["render",s]]);export{f as __pageData,m as default};
